mapper.select:
SELECT b.id, b.building_name, b.building_code, b.community_id, c.community_name, b.above_ground_floors, b.underground_floors, b.units_per_floor, b.building_type, b.status, b.remark, b.create_time, b.update_time FROM bs_building b LEFT JOIN bs_community c ON b.community_id = c.id WHERE b.del_flag = 0
AND b.building_name LIKE CONCAT('%', #{query.buildingName}, '%')
AND b.building_code LIKE CONCAT('%', #{query.buildingCode}, '%')
AND b.community_id = #{query.communityId}
AND b.building_type = #{query.buildingType}
AND b.status = #{query.status}
ORDER BY b.create_time DESC
